function interpolatePrompt(prompt, vars) {
  return prompt.replace(/\{\{CWD\}\}/g, vars.cwd).replace(/\{\{SESSION_ID\}\}/g, vars.sessionId).replace(/\{\{MODEL\}\}/g, vars.model ?? "unknown");
}

// src/agents/builtin-agents.ts
function makeFactory(opts) {
  const {
    name,
    description,
    promptTemplate,
    defaultModel,
    temperature = 0.3,
    mode = "all",
    cost = "expensive",
    readOnly = false,
    deniedTools,
    recommendedSkills,
    preferredCapabilities
  } = opts;
  return {
    name,
    description,
    mode,
    cost,
    create(model, overrides) {
      return {
        name,
        description,
        systemPrompt: promptTemplate,
        model: overrides?.model ?? model ?? defaultModel,
        temperature: overrides?.temperature ?? temperature,
        mode,
        cost,
        readOnly,
        deniedTools,
        recommendedSkills,
        preferredCapabilities,
        ...overrides
      };
    }
  };
}
